// Auto-generated blog content
export const content: string = "<!-- CONTENIDO DEL BLOG -->\n  <article class=\"blog-article\">\n\n    <div class=\"article-meta\">\n      <span>\ud83d\udcc5 Actualizado: Noviembre 2025</span>\n      <span>\u23f1\ufe0f 8 min lectura</span>\n      <span>\ud83d\udcca Basado en F\u00f3rmulas WSAVA</span>\n    </div>\n\n    <h1>Cu\u00e1nto Debe Comer un Perro Seg\u00fan su Peso: Tabla Completa 2025</h1>\n\n    <p>Si alguna vez te has preguntado <strong>\"\u00bfcu\u00e1nto debe comer mi perro?\"</strong>, no est\u00e1s solo. M\u00e1s del 59% de los perros tienen sobrepeso porque muchos tutores (con toda la intenci\u00f3n de hacerlo bien) terminan dando porciones que no encajan con su perro real.</p>\n\n    <p>En esta gu\u00eda respaldada por f\u00f3rmulas veterinarias certificadas (WSAVA), aprender\u00e1s <strong>cu\u00e1ntos gramos de alimento</strong> necesita tu perro seg\u00fan su peso, edad y nivel de actividad. Y tambi\u00e9n c\u00f3mo usar ese n\u00famero en el d\u00eda a d\u00eda, sin rigidez.</p>\n\n    <div class=\"highlight-box\">\n      \ud83c\udfaf <strong>Resultado garantizado:</strong> Al terminar esta gu\u00eda, sabr\u00e1s la porci\u00f3n aproximada que tu perro necesita y c\u00f3mo afinarla con nuestra calculadora personalizada gratuita.\n    </div>\n\n    <!-- Tabla de Contenidos -->\n    <div class=\"toc\">\n      <h3>\ud83d\udccb Contenido de la Gu\u00eda</h3>\n      <ol>\n        <li><a href=\"#tabla-rapida\">Tabla R\u00e1pida por Peso (5kg a 40kg+)</a></li>\n        <li><a href=\"#factores\">5 Factores que Afectan las Porciones</a></li>\n        <li><a href=\"#edad\">Ajustes por Edad (Cachorro, Adulto, Senior)</a></li>\n        <li><a href=\"#actividad\">Ajustes por Nivel de Actividad</a></li>\n        <li><a href=\"#como-medir\">C\u00f3mo Medir las Porciones Correctamente</a></li>\n        <li><a href=\"#errores\">7 Errores Comunes al Alimentar</a></li>\n        <li><a href=\"#calculadora\">Calculadora Personalizada (Gratis)</a></li>\n        <li><a href=\"#faq\">Preguntas Frecuentes</a></li>\n      </ol>\n    </div>\n\n    <h2 id=\"tabla-rapida\">\ud83d\udcca Tabla R\u00e1pida: Cu\u00e1nto Debe Comer un Perro Seg\u00fan su Peso</h2>\n\n    <p>Esta tabla muestra las porciones aproximadas para un <strong>perro adulto (1-7 a\u00f1os) con actividad moderada</strong> que come alimento seco est\u00e1ndar (\u2248350 kcal/100g).</p>\n\n    <div class=\"warning-box\">\n      \u26a0\ufe0f <strong>Importante:</strong> Estas son estimaciones generales. Para un c\u00e1lculo exacto personalizado, usa nuestra <a href=\"#calculadora\" style=\"color: #667e6d; font-weight: 700;\">calculadora gratuita</a> al final del art\u00edculo.\n    </div>\n\n    <div class=\"table-container\">\n      <table>\n        <thead>\n          <tr>\n            <th>Peso del Perro</th>\n            <th>Calor\u00edas/D\u00eda</th>\n            <th>Gramos/D\u00eda</th>\n            <th>Comidas/D\u00eda</th>\n          </tr>\n        </thead>\n        <tbody>\n          <tr>\n            <td class=\"weight-range\">5 kg (Muy Peque\u00f1o)</td>\n            <td class=\"calories\">300-350 kcal</td>\n            <td class=\"grams\">85-100g</td>\n            <td>2-3 comidas</td>\n          </tr>\n          <tr>\n            <td class=\"weight-range\">10 kg (Peque\u00f1o)</td>\n            <td class=\"calories\">500-550 kcal</td>\n            <td class=\"grams\">140-160g</td>\n            <td>2 comidas</td>\n          </tr>\n          <tr>\n            <td class=\"weight-range\">15 kg (Mediano-Peque\u00f1o)</td>\n            <td class=\"calories\">700-750 kcal</td>\n            <td class=\"grams\">200-215g</td>\n            <td>2 comidas</td>\n          </tr>\n          <tr>\n            <td class=\"weight-range\">20 kg (Mediano)</td>\n            <td class=\"calories\">880-950 kcal</td>\n            <td class=\"grams\">250-270g</td>\n            <td>2 comidas</td>\n          </tr>\n          <tr>\n            <td class=\"weight-range\">25 kg (Mediano-Grande)</td>\n            <td class=\"calories\">1,050-1,100 kcal</td>\n            <td class=\"grams\">300-315g</td>\n            <td>2 comidas</td>\n          </tr>\n          <tr>\n            <td class=\"weight-range\">30 kg (Grande)</td>\n            <td class=\"calories\">1,200-1,250 kcal</td>\n            <td class=\"grams\">340-360g</td>\n            <td>2 comidas</td>\n          </tr>\n          <tr>\n            <td class=\"weight-range\">35 kg (Grande)</td>\n            <td class=\"calories\">1,350-1,400 kcal</td>\n            <td class=\"grams\">385-400g</td>\n            <td>2 comidas</td>\n          </tr>\n          <tr>\n            <td class=\"weight-range\">40+ kg (Muy Grande)</td>\n            <td class=\"calories\">1,500-1,650 kcal</td>\n            <td class=\"grams\">430-470g</td>\n            <td>2 comidas</td>\n          </tr>\n        </tbody>\n      </table>\n    </div>\n\n    <div class=\"tip-box\">\n      \ud83d\udca1 <strong>Consejo Profesional:</strong> Divide la porci\u00f3n diaria en 2 comidas (ma\u00f1ana y tarde/noche). Esto ayuda a mantener su metabolismo estable y evita que llegue con demasiada ansiedad a la siguiente comida.\n    </div>\n\n    <!-- \u2705 CAPA DE EXPERIENCIA (DogNavi) -->\n    <div class=\"success-box\">\n      \ud83e\udde0 <strong>Criterio real desde DogNavi:</strong>\n      <p style=\"margin-top: 0.7rem;\">En DogNavi hemos visto algo muy claro: la mayor\u00eda de los problemas de peso no empiezan por \u201chacerlo mal\u201d, sino por peque\u00f1as decisiones diarias que se van acumulando.</p>\n      <p style=\"margin-top: 0.7rem;\">Un error muy com\u00fan en tutores es pensar que \u201cun poquito m\u00e1s no hace da\u00f1o\u201d, especialmente cuando el perro pide comida o parece tener hambre todo el tiempo.</p>\n      <p style=\"margin-top: 0.7rem;\">En la pr\u00e1ctica, ese extra diario suele ser la diferencia. Es como agregar una cucharada m\u00e1s de az\u00facar al caf\u00e9 todos los d\u00edas: no se nota hoy, pero con el tiempo deja huella.</p>\n    </div>\n\n    <h2 id=\"factores\">\ud83e\uddec 5 Factores que Afectan Cu\u00e1nto Debe Comer tu Perro</h2>\n\n    <p>La tabla anterior es un punto de partida, pero cada perro es \u00fanico. Aqu\u00ed est\u00e1n los 5 factores principales que debes considerar:</p>\n\n    <h3>1. Peso y Tama\u00f1o</h3>\n    <p>Obvio, pero hay un detalle importante: <strong>los perros peque\u00f1os tienen un metabolismo m\u00e1s r\u00e1pido</strong>. Un Chihuahua de 3kg necesita proporcionalmente m\u00e1s calor\u00edas por kg que un Gran Dan\u00e9s de 60kg.</p>\n\n    <p><strong>Regla pr\u00e1ctica:</strong> Perros peque\u00f1os (\u226410kg) necesitan ~40-50 kcal/kg. Perros grandes (\u226530kg) necesitan ~30-35 kcal/kg.</p>\n\n    <h3>2. Edad</h3>\n    <p>Las necesidades cal\u00f3ricas var\u00edan dram\u00e1ticamente con la edad:</p>\n    <ul>\n      <li><strong>Cachorros (0-12 meses):</strong> Necesitan 2-3x m\u00e1s calor\u00edas (est\u00e1n creciendo)</li>\n      <li><strong>Adultos (1-7 a\u00f1os):</strong> Requerimientos \"est\u00e1ndar\"</li>\n      <li><strong>Seniors (7+ a\u00f1os):</strong> Necesitan 20-30% menos calor\u00edas (metabolismo m\u00e1s lento)</li>\n    </ul>\n\n    <h3>3. Nivel de Actividad</h3>\n    <p>Un perro que corre 10km diarios NO puede comer lo mismo que uno que solo sale 15 minutos. Aqu\u00ed el cuerpo manda: si gasta m\u00e1s, necesita m\u00e1s.</p>\n    <ul>\n      <li><strong>Baja actividad:</strong> Reduce 15-20% las porciones de la tabla</li>\n      <li><strong>Actividad moderada:</strong> Usa la tabla tal cual</li>\n      <li><strong>Alta actividad:</strong> Aumenta 20-30% las porciones</li>\n    </ul>\n\n    <h3>4. Esterilizaci\u00f3n/Castraci\u00f3n</h3>\n    <p>Los perros esterilizados necesitan <strong>10-15% menos calor\u00edas</strong> porque su metabolismo se reduce. Si tu perro fue esterilizado recientemente, ajusta las porciones gradualmente.</p>\n\n    <h3>5. Condici\u00f3n Corporal Actual</h3>\n    <p>Si tu perro ya tiene sobrepeso, necesita un d\u00e9ficit cal\u00f3rico controlado. Si est\u00e1 bajo de peso, necesita m\u00e1s calor\u00edas.</p>\n\n    <div class=\"success-box\">\n      \u2705 <strong>Test r\u00e1pido:</strong> Pon tus manos a ambos lados de su pecho. \u00bfSientes las costillas con presi\u00f3n ligera pero no las ves? = Peso ideal. \u00bfTienes que presionar fuerte? = Sobrepeso. \u00bfLas ves marcadas? = Bajo peso.\n    </div>\n\n    <!-- \u2705 CU\u00c1NDO NO ES SUFICIENTE -->\n    <div class=\"warning-box\">\n      \u26a0\ufe0f <strong>Cu\u00e1ndo NO debes usar solo esta gu\u00eda</strong>\n      <p style=\"margin-top: 0.7rem;\">Esta tabla y recomendaciones funcionan muy bien como referencia general, pero no son suficientes si tu perro:</p>\n      <ul style=\"margin: 0.8rem 0 0 1.2rem;\">\n        <li>Tiene una enfermedad diagnosticada (diabetes, problemas renales, hep\u00e1ticos o digestivos).</li>\n        <li>Est\u00e1 siguiendo una dieta terap\u00e9utica indicada por un veterinario.</li>\n        <li>Es un cachorro de raza grande en crecimiento acelerado.</li>\n        <li>Ha perdido o ganado peso r\u00e1pidamente en pocas semanas.</li>\n      </ul>\n      <p style=\"margin-top: 0.7rem;\"><strong>En estos casos</strong>, la porci\u00f3n debe ajustarse de forma individual con supervisi\u00f3n profesional.</p>\n    </div>\n\n    <!-- \u2705 USO REAL DE LA CALCULADORA (ANTES DEL CTA) -->\n    <div class=\"tip-box\">\n      \ud83e\uddee <strong>C\u00f3mo usar correctamente la calculadora de DogNavi</strong>\n      <p style=\"margin-top: 0.7rem;\">La calculadora no \u201cadivina\u201d cu\u00e1nto debe comer tu perro. Lo que hace bien es ordenar los factores que m\u00e1s influyen: peso, edad, actividad, esterilizaci\u00f3n y condici\u00f3n corporal.</p>\n      <p style=\"margin-top: 0.7rem;\">Tambi\u00e9n es importante saber lo que <strong>NO</strong> hace: no reemplaza una dieta veterinaria espec\u00edfica, no detecta enfermedades y no corrige datos incorrectos (por ejemplo, un peso estimado \u201ca ojo\u201d).</p>\n      <p style=\"margin-top: 0.7rem;\">\u00dasala como un <strong>punto de partida preciso</strong>. Piensa en ella como un GPS: te marca la mejor ruta con lo que le das, pero t\u00fa sigues conduciendo. Observa a tu perro durante 2\u20133 semanas y ajusta si algo no cuadra.</p>\n    </div>\n\n    <div class=\"cta-box\">\n      <h3>\ud83e\uddee \u00bfQuieres el C\u00e1lculo Exacto para TU Perro?</h3>\n      <p>Nuestra calculadora considera todos estos factores autom\u00e1ticamente: peso, edad, actividad, esterilizaci\u00f3n y condici\u00f3n corporal.</p>\n      <a href=\"/#calculadora\" class=\"btn\">Calcular Porciones Gratis</a>\n    </div>\n\n    <h2 id=\"edad\">\ud83d\udc76\ud83d\udc15\u200d\ud83e\uddba\ud83d\udc74 Ajustes por Edad: Cachorro, Adulto y Senior</h2>\n\n    <h3>Cachorros (0-12 Meses)</h3>\n    <p>Los cachorros est\u00e1n en pleno crecimiento y tienen necesidades especiales:</p>\n    <ul>\n      <li><strong>0-3 meses:</strong> 3-4 comidas al d\u00eda (su est\u00f3mago es peque\u00f1o)</li>\n      <li><strong>3-6 meses:</strong> 3 comidas al d\u00eda</li>\n      <li><strong>6-12 meses:</strong> 2-3 comidas al d\u00eda</li>\n      <li><strong>Calor\u00edas:</strong> 2-3x m\u00e1s que un adulto del mismo peso</li>\n    </ul>\n\n    <div class=\"warning-box\">\n      \u26a0\ufe0f <strong>Error com\u00fan:</strong> Sobrealimentar cachorros de razas grandes (Labrador, Pastor Alem\u00e1n) puede causar problemas \u00f3seos. Sigue las recomendaciones veterinarias estrictamente.\n    </div>\n\n    <h3>Adultos (1-7 A\u00f1os)</h3>\n    <p>Esta es la etapa m\u00e1s \"estable\". Usa la tabla principal y ajusta seg\u00fan actividad y condici\u00f3n corporal.</p>\n\n    <p><strong>Monitoreo mensual:</strong> Pesa a tu perro una vez al mes. Si sube o baja m\u00e1s de 5% de su peso, ajusta las porciones.</p>\n\n    <h3>Seniors (7+ A\u00f1os)</h3>\n    <p>Los perros mayores suelen necesitar menos calor\u00edas pero m\u00e1s atenci\u00f3n. No es \u201cquitarle comida\u201d, es cuidar su equilibrio.</p>\n    <ul>\n      <li><strong>Reduce calor\u00edas 20-30%</strong> (metabolismo m\u00e1s lento)</li>\n      <li><strong>Mant\u00e9n 2 comidas diarias</strong> (ayuda digesti\u00f3n)</li>\n      <li><strong>Considera alimento senior</strong> (m\u00e1s fibra, menos grasa)</li>\n      <li><strong>Suplementos articulares</strong> pueden ser necesarios</li>\n    </ul>\n\n    <p><strong>Ejemplo:</strong> Un senior de 20kg que antes com\u00eda 260g/d\u00eda, ahora necesita ~200-210g/d\u00eda</p>\n\n    <h2 id=\"actividad\">\ud83c\udfc3\u200d\u2642\ufe0f Ajustes por Nivel de Actividad</h2>\n\n    <p>No todos los perros necesitan las mismas calor\u00edas aunque pesen igual. Aqu\u00ed c\u00f3mo ajustar:</p>\n\n    <h3>Baja Actividad (Sedentario)</h3>\n    <p><strong>Perfil t\u00edpico:</strong> Vive en departamento, sale 2-3 veces al d\u00eda solo para hacer sus necesidades (10-20 min totales), duerme la mayor parte del d\u00eda.</p>\n    <p><strong>Ajuste:</strong> Reduce 15-20% la porci\u00f3n de la tabla</p>\n\n    <h3>Actividad Moderada (Est\u00e1ndar)</h3>\n    <p>El perfil est\u00e1ndar para el que est\u00e1 hecha la tabla.</p>\n\n    <h3>Alta Actividad (Deportista)</h3>\n    <p><strong>Perfil t\u00edpico:</strong> Corre diariamente, practica agility, canicross o pastoreo.</p>\n    <p><strong>Ajuste:</strong> Aumenta 25-40% la porci\u00f3n.</p>\n\n    <div class=\"tip-box\">\n      \ud83d\udca1 <strong>Truco:</strong> Si notas que tu perro pierde peso a pesar de comer lo recomendado, probablemente necesita m\u00e1s calor\u00edas. Aumenta 10% cada semana hasta que se estabilice.\n    </div>\n\n    <h2 id=\"como-medir\">\u2696\ufe0f C\u00f3mo Medir las Porciones Correctamente</h2>\n\n    <p>El error #1 que cometen los due\u00f1os: medir \"a ojo\".</p>\n\n    <h3>M\u00e9todo 1: B\u00e1scula de Cocina (El Mejor)</h3>\n    <ol>\n      <li>Pon el bowl vac\u00edo en la b\u00e1scula \u2192 Tara</li>\n      <li>Agrega alimento hasta llegar al peso exacto</li>\n      <li>Sirve</li>\n    </ol>\n\n    <h3>M\u00e9todo 2: Taza Medidora</h3>\n    <p>Menos preciso. La densidad de las croquetas var\u00eda.</p>\n\n    <h3>M\u00e9todo 3: Comedero Autom\u00e1tico</h3>\n    <p>Preciso y pr\u00e1ctico, pero m\u00e1s caro.</p>\n\n    <div class=\"warning-box\">\n      \u26a0\ufe0f <strong>Nunca olvides:</strong> Los premios tambi\u00e9n cuentan. Si das premios diarios, reduce 10-15% la comida o usa parte de su porci\u00f3n como premio.\n    </div>\n\n    <h2 id=\"errores\">\ud83d\udeab 7 Errores Comunes al Alimentar a tu Perro</h2>\n\n    <h3>Error #1: Seguir el Paquete Ciegamente</h3>\n    <p>Las marcas suelen recomendar m\u00e1s de lo necesario. No significa que sea \u201cmalo\u201d, pero no est\u00e1 personalizado.</p>\n\n    <h3>Error #2: No Ajustar por Premios</h3>\n    <p>Pueden representar 30% de calor\u00edas extra.</p>\n\n    <h3>Error #3: Dar Sobras de Mesa</h3>\n    <p>Adem\u00e1s de sumar calor\u00edas, muchas sobras no son adecuadas para perros (por sal, grasa o ingredientes irritantes).</p>\n\n    <h3>Error #4: Ignorar la Esterilizaci\u00f3n</h3>\n    <p>Despu\u00e9s de esterilizar, muchos perros ganan peso si no se ajusta la porci\u00f3n a tiempo.</p>\n\n    <h3>Error #5: Medir a Ojo</h3>\n    <p>La variaci\u00f3n diaria parece peque\u00f1a, pero a la larga funciona como un \u201ctermostato\u201d mal calibrado: se va moviendo sin que lo notes.</p>\n\n    <h3>Error #6: Cambiar de Alimento de Golpe</h3>\n    <ul>\n      <li>D\u00eda 1-3: 75% viejo + 25% nuevo</li>\n      <li>D\u00eda 4-6: 50% + 50%</li>\n      <li>D\u00eda 7-10: 25% + 75%</li>\n    </ul>\n\n    <h3>Error #7: No Monitorear Condici\u00f3n Corporal</h3>\n    <p>La tabla ayuda, pero tu perro es quien da la \u00faltima se\u00f1al. Si algo no cuadra, ajusta con calma.</p>\n\n    <!-- \u2705 ENGANCHE POST-LECTURA -->\n    <div class=\"highlight-box\">\n      \ud83d\udccc <strong>Qu\u00e9 hacer despu\u00e9s de calcular la porci\u00f3n</strong>\n      <p style=\"margin-top: 0.7rem;\">Calcular la cantidad correcta es solo el primer paso. Para que funcione en la vida real:</p>\n      <ol style=\"margin: 0.8rem 0 0 1.2rem;\">\n        <li>Mide con b\u00e1scula al menos la primera semana.</li>\n        <li>Divide la cantidad diaria en 2 comidas.</li>\n        <li>Observa energ\u00eda, heces y apetito durante 14 d\u00edas.</li>\n      </ol>\n      <p style=\"margin-top: 0.7rem;\">Si tu perro pide comida constantemente, no siempre es falta de cantidad. Muchas veces es rutina aprendida (como cuando nosotros abrimos el refri por costumbre).</p>\n      <p style=\"margin-top: 0.7rem;\"><strong>Siguiente paso recomendado:</strong> revisa tambi\u00e9n estas gu\u00edas:</p>\n      <ul style=\"margin: 0.8rem 0 0 1.2rem;\">\n        <li><a href=\"/blog/senales-sobrealimentacion\" style=\"color:#667e6d; font-weight:700;\">10 se\u00f1ales de que tu perro est\u00e1 sobrealimentado</a></li>\n        <li><a href=\"/blog/perro-no-quiere-comer-causas-soluciones\" style=\"color:#667e6d; font-weight:700;\">Mi perro no quiere comer: causas y soluciones</a></li>\n      </ul>\n    </div>\n\n    <div class=\"related-products\">\n      <h3>\ud83d\uded2 Herramientas Recomendadas</h3>\n\n      <div class=\"product-grid\">\n\n        <!-- PRODUCTO 1 -->\n        <div class=\"product-card\">\n          <img src=\"/images/productos/premios nupec.webp\" alt=\"Nupec Premios Relax Anti Estr\u00e9s 180 Gr\" class=\"product-img\" loading=\"lazy\">\n          <h4>Nupec Premios Relax Anti Estr\u00e9s 180 Gr</h4>\n          <p>Los Premios Nupec Relax Care de 180g son una deliciosa golosina dise\u00f1ada espec\u00edficamente para perros, con un sabor irresistible a pollo que har\u00e1 que tu mascota no pueda resistirse.</p>\n          <a href=\"https://mercadolibre.com/sec/2nBzqnR\" target=\"_blank\" class=\"btn-product\">Ver precio en Mercado Libre \u2192</a>\n        </div>\n\n        <!-- PRODUCTO 3 -->\n        <div class=\"product-card\">\n          <img src=\"/images/productos/hueso_masticable.webp\" alt=\"Hueso De Carnaza Natural 8-10 Cm 25 Piezas\" class=\"product-img\" loading=\"lazy\">\n          <h4>Hueso De Carnaza Natural 8-10 Cm 25 Piezas</h4>\n          <p>Satisface la necesidad natural de morder, reduce ansiedad y mantiene a tu perro entretenido por m\u00e1s tiempo. Ideal para evitar que muerda muebles y para complementar su gasto de energ\u00eda diario.</p>\n          <a href=\"https://mercadolibre.com/sec/2xdMgdM\" target=\"_blank\" class=\"btn-product\">Ver precio en Mercado Libre \u2192</a>\n        </div>\n\n        <!-- PRODUCTO 4 -->\n        <div class=\"product-card\">\n          <img src=\"/images/productos/cepillo.webp\" alt=\"Cepillo\" class=\"product-img\" loading=\"lazy\">\n          <h4>3 In 1 Depilaci\u00f3n Cepillo De Vapor Para Gato/perro Mascota</h4>\n          <p>Elimina pelo suelto, desenreda y suaviza el pelaje con ayuda de vapor. Reduce la ca\u00edda de pelo en casa, evita nudos y deja el manto limpio y brillante en pocos minutos. Ideal para perros y gatos de cualquier tama\u00f1o.</p>\n          <a href=\"https://mercadolibre.com/sec/2HpZtLW\" target=\"_blank\" class=\"btn-product\">Ver precio en Mercado Libre \u2192</a>\n        </div>\n\n      </div>\n    </div>\n\n    <div class=\"cta-box\" id=\"calculadora\">\n      <h3>\ud83c\udfaf Calcula la Porci\u00f3n Exacta</h3>\n      <p>Considera peso, edad, actividad, esterilizaci\u00f3n y condici\u00f3n corporal.</p>\n      <a href=\"/#calculadora\" class=\"btn\">Usar Calculadora Gratis</a>\n    </div>\n\n    <h2 id=\"faq\">\u2753 Preguntas Frecuentes</h2>\n\n    <div class=\"faq-section\">\n      <div class=\"faq-item\">\n        <div class=\"faq-question\">\u00bfCu\u00e1ntas veces al d\u00eda debe comer un perro adulto?</div>\n        <div class=\"faq-answer\">2 veces al d\u00eda es lo ideal.</div>\n      </div>\n\n      <div class=\"faq-item\">\n        <div class=\"faq-question\">Mi perro siempre pide comida, \u00bfes normal?</div>\n        <div class=\"faq-answer\">S\u00ed. Muchos perros comen por instinto oportunista o por rutina. Eso no siempre significa que necesiten m\u00e1s comida.</div>\n      </div>\n\n      <div class=\"faq-item\">\n        <div class=\"faq-question\">\u00bfSi come h\u00famedo cambia la cantidad?</div>\n        <div class=\"faq-answer\">S\u00ed. El alimento h\u00famedo tiene mucha agua y suele requerir m\u00e1s gramos para equivaler a las mismas calor\u00edas. Revisa siempre kcal por porci\u00f3n en la etiqueta.</div>\n      </div>\n\n      <div class=\"faq-item\">\n        <div class=\"faq-question\">\u00bfDebo ajustar si est\u00e1 esterilizado?</div>\n        <div class=\"faq-answer\">S\u00ed. En promedio, reduce 10-15% las porciones y observa 2-3 semanas antes de volver a ajustar.</div>\n      </div>\n\n      <div class=\"faq-item\">\n        <div class=\"faq-question\">\u00bfCuenta como calor\u00edas lo que le doy de premios?</div>\n        <div class=\"faq-answer\">S\u00ed. Idealmente, los premios no deber\u00edan superar el 10% de sus calor\u00edas diarias.</div>\n      </div>\n    </div>\n\n    <h2>\ud83c\udfc1 Conclusi\u00f3n</h2>\n\n    <p>No necesitas hacerlo perfecto. Necesitas hacerlo <strong>medible, constante y humano</strong>.</p>\n    <p>La tabla ayuda. La calculadora orienta. Pero tu perro es quien da la \u00faltima se\u00f1al.</p>\n\n    <ol>\n      <li>Pesa a tu perro</li>\n      <li>Usa la calculadora</li>\n      <li>Mide con b\u00e1scula</li>\n      <li>Divide en 2 comidas</li>\n      <li>Monitorea mensual</li>\n    </ol>\n\n    <div class=\"success-box\">\n      \u2705 <strong>En 2-3 semanas:</strong> mejor energ\u00eda, digesti\u00f3n y un peso m\u00e1s estable.\n    </div>\n\n    <div class=\"cta-box\">\n      <h3>\ud83d\udcca Da el Primer Paso</h3>\n      <p>Calcula gratis la alimentaci\u00f3n ideal para tu perro y aprende a interpretarla en el d\u00eda a d\u00eda.</p>\n      <a href=\"/#calculadora\" class=\"btn\">Usar Calculadora</a>\n    </div>\n\n    <div class=\"sources\">\n      <h4>\ud83d\udcda Fuentes Cient\u00edficas</h4>\n      <ul>\n        <li>WSAVA Nutrition Guidelines</li>\n        <li>AKC Canine Nutrition</li>\n        <li>ASPCA Pet Nutrition</li>\n        <li>Merck Veterinary Manual</li>\n        <li>NRC Nutrient Requirements</li>\n      </ul>\n      <p><strong>Nota:</strong> Esto no reemplaza asesor\u00eda veterinaria.</p>\n    </div>\n\n    <div style=\"margin-top:3rem; padding-top:2rem; border-top:2px solid #F4EDE4; text-align:center;\">\n      <p style=\"font-size:0.95rem; color:#666;\">\n        <strong>Actualizado:</strong> Noviembre 2025 \u2022\n        <strong>Pr\u00f3xima revisi\u00f3n:</strong> Febrero 2026\n      </p>\n    </div>\n\n  </article>\n\n  <!-- FOOTER DIN\u00c1MICO -->";
